import{c as e,a7 as i,y as r,B as t}from"./chunks/framework.3cjvm90C.js";const P=JSON.parse('{"title":"MPI","description":"MPI 消息传递接口的基本概念与在分布式训练中的应用","frontmatter":{"title":"MPI","description":"MPI 消息传递接口的基本概念与在分布式训练中的应用"},"headers":[],"relativePath":"dlwiki/distributed-training/mpi.md","filePath":"dlwiki/distributed-training/mpi.md","lastUpdated":1782456021000}'),o={name:"dlwiki/distributed-training/mpi.md"};function l(n,a,c,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="mpi" tabindex="-1">MPI <a class="header-anchor" href="#mpi" aria-label="Permalink to “MPI”">​</a></h1><p>说到并行计算，我们有一个不可绕开的话题——MPI 编程。MPI 是一个跨语言的通讯协议，用于编写并行计算机。支持点对点和广播。MPI 是一个信息传递应用程序接口，包括协议和和语义说明，他们指明其如何在各种实现中发挥其特性。MPI 的目标是高性能，大规模性，和可移植性。MPI 在今天仍为<a href="https://cloud.tencent.com/solution/hpc?from=10680" target="_blank" rel="noreferrer">高性能计算</a>的主要模型。与 OpenMP 并行程序不同，MPI 是一种基于信息传递的并行编程技术。消息传递接口是一种编程接口标准，而不是一种具体的编程语言。简而言之，MPI 标准定义了一组具有可移植性的编程接口。</p><h2 id="什么是-mpi" tabindex="-1">什么是 MPI <a class="header-anchor" href="#什么是-mpi" aria-label="Permalink to “什么是 MPI”">​</a></h2><p>对 MPI 的定义是多种多样的， 但不外乎下面三个方面， 它们限定了 MPI 的内涵和外延。</p><ul><li><p>MPI 是一个库 而不是一门语言 。 MPI 库可以被 FORTRAN77/C/Fortran90/C++调用 从语法上说，它遵守所有对库函数/过程的调用规则，和一般的函数/过程没有什么区别。</p></li><li><p>MPI 是一种标准或规范的代表， 而不特指某一个对它的具体实现。 迄今为止 ，所有的并行计算机制造商都提供对 MPI 的支持， 可以在网上免费得到 MPI 在不同并行计算机上的实现， 一个正确的 MPI 程序 ，可以不加修改地在所有的并行机上运行。</p></li><li><p>MPI 是一种消息传递编程模型， 并成为这种编程模型的代表和事实上的标准。 MPI 虽然很庞大， 但是它的最终目的是服务于进程间通信这一目标的。</p></li></ul><p>​ 在 MPI 上很容易移植其它的并行代码， 而且编程者不需要去努力掌握许多其它的全新概念， 就可以学习编写 MPI 程序， 当然 这并不意味着 MPI 已经十分完美， 必须承认 MPI 自身还存在着一些缺点。</p><p>​ 消息传递方式是广泛应用于多类并行机的一种模式,特别是那些分布存储并行机 , 尽管在具体的实现上有许多不同, 但通过消息完成进程通信的基本概念是容易理解的。 十多年来， 这种模式在重要的计算应用中已取得了实质进步 。有效和可移植地实现一个消息传递系统是可行的， 因此， 通过定义核心库程序的语法， 语义， 这将在大范围计算机上可有效实现，将有益于广大用户 ，这是 MPI 产生的重要原因 。</p><h2 id="mpi-的目的" tabindex="-1">MPI 的目的 <a class="header-anchor" href="#mpi-的目的" aria-label="Permalink to “MPI 的目的”">​</a></h2><p>MPI 为自己制定了一个雄心勃勃的目标 ，总结概括起来 ，它包括几个在实际使用中都十分重要但有时又是相互矛盾的三个方面 ：1 较高的通信性能 ；2 较好的程序可移植性； 3 强大的功能 。具体地说 包括以下几个方面：</p><ul><li>提供应用程序编程接口</li><li>提高通信效率， 措施包括避免存储器到存储器的多次重复拷贝， 允许计算和通信的重叠等</li><li>可在异构环境下提供实现</li><li>提供的接口可以方便 C 语言和 Fortran 77 的调用</li><li>提供可靠的通信接口 ，即用户不必处理通信失败</li><li>定义的接口和现在已有接口 ，如（PVM NX Express p4 等） 差别不能太大， 但是允许扩展以提供更大的灵活性</li><li>定义的接口能在基本的通信和系统软件无重大改变时， 在许多并行计算机生产商的平台上实现。 接口的语义是独立于语言的</li><li>接口设计应是线程安全的</li></ul><p>​ MPI 提供了一种与语言和平台无关， 可以被广泛使用的编写消息传递程序的标准 ，用它来编写消息传递程序 ，不仅实用 ，可移植 ，高效和灵活， 而且和当前已有的实现没有太大的变化 。</p><h2 id="名词和概念" tabindex="-1">名词和概念 <a class="header-anchor" href="#名词和概念" aria-label="Permalink to “名词和概念”">​</a></h2><p><strong>程序代码：</strong></p><p>这里的程序不是指以文件形式存在的源代码、可执行代码等，而是指为了完成一个计算任务而进行的一次运行过程。</p><p><strong>进程(Process)</strong></p><p>一个 MPI 并行程序由一组运行在相同或不同计算机 /计算节点上的进程或线程构成。为统一起见，我们将 MPI 程序中一个独立参与通信的个体称为一个进程。</p><p><strong>进程组：</strong></p><p>一个 MPI 程序的全部进程集合的一个有序子集。进程组中每个进程都被赋予一个在改组中唯一的序号（rank），用于在该组中标识该进程。序号范围从 0 到进程数－1。</p><p><strong>通信器（communicator）:</strong></p><p>有时也译成通信子，是完成进程间通信的基本环境，它描述了一组可以互相通信的进程以及它们之间的联接关系等信息。MPI 所有通信必须在某个通信器中进行。通信器分域内通信器（intracommunicator）和域间通信器（intercommunicator）两类，前者用于同一进程中进程间的通信，后者则用于分属不同进程的进程间的通信。</p><p>MPI 系统在一个 MPI 程序运行时会自动创建两个通信器：一个称为 MPI_COMM_WORLD，它包含 MPI 程序中所有进程，另一个称为 MPI_COMM_SELF，它指单个进程自己所构成的通信器。</p><p><strong>序号（rank）：</strong></p><p>即进程的标识，是用来在一个进程组或一个通信器中标识一个进程。MPI 的进程由进程组/序号或通信器/序号唯一确定。</p><p><strong>消息（message）：</strong></p><p>MPI 程序中在进程间传递的数据。它由通信器、源地址、目的地址、消息标签和数据构成。</p><p><strong>通信（communication）：</strong></p><p>通信是指在进程之间进行消息的收发、同步等操作。</p><h2 id="mpi-核心接口" tabindex="-1">MPI 核心接口 <a class="header-anchor" href="#mpi-核心接口" aria-label="Permalink to “MPI 核心接口”">​</a></h2><p>用过 Hadoop 的童鞋应该都记得经典的 Map 和 Reduce 接口，我们在写 MR 程序的时候主要就在写自己实现的 Map 和 Reduce 方法。</p><p>MPI 比 Hadoop 需要关注的稍微多一点点。</p><p><strong>注意：</strong> 这几个核心的接口还是要了解一下的。暂时可以看一眼跳过去，后面在看程序的时候回过头多对比一下就能记住了。</p><p>我们简单地理解一下这 6 个接口，其实可以分为 3 类：</p><ol><li>开始和结束 MPI 的接口：<code>MPI_Init</code>、 <code>MPI_Finalize</code></li><li>获取进程状态的接口：<code>MPI_Comm_rank</code>、<code>MPI_Comm_size</code></li><li>传输数据的接口：<code>MPI_Send</code>、<code>MPI_Recv</code></li></ol><h4 id="_1-mpi-init-argc-argv" tabindex="-1">1. <code>MPI_Init(&amp;argc, &amp;argv)</code> <a class="header-anchor" href="#_1-mpi-init-argc-argv" aria-label="Permalink to “1. MPI_Init(&amp;argc, &amp;argv)”">​</a></h4><p>初始化 MPI 执行环境，建立多个 MPI 进程之间的联系，为后续通信做准备。</p><h4 id="_2-mpi-comm-rank-communicator-myid" tabindex="-1">2. <code>MPI_Comm_rank(communicator, &amp;myid)</code> <a class="header-anchor" href="#_2-mpi-comm-rank-communicator-myid" aria-label="Permalink to “2. MPI_Comm_rank(communicator, &amp;myid)”">​</a></h4><p>用来标识各个 MPI 进程的，给出调用该函数的进程的进程号,返回整型的错误值。两个参数：MPI_Comm 类型的通信域，标识参与计算的 MPI 进程组； &amp;rank 返回调用进程中的标识号。</p><h4 id="_3-mpi-comm-size-communicator-numprocs" tabindex="-1">3. <code>MPI_Comm_size(communicator, &amp;numprocs)</code> <a class="header-anchor" href="#_3-mpi-comm-size-communicator-numprocs" aria-label="Permalink to “3. MPI_Comm_size(communicator, &amp;numprocs)”">​</a></h4><p>用来标识相应进程组中有多少个进程。</p><h4 id="_4-mpi-finalize" tabindex="-1">4. <code>MPI_Finalize()</code> <a class="header-anchor" href="#_4-mpi-finalize" aria-label="Permalink to “4. MPI_Finalize()”">​</a></h4><p>结束 MPI 执行环境。</p><h4 id="_5-mpi-send-buf-counter-datatype-dest-tag-comm" tabindex="-1">5. <code>MPI_Send(buf,counter,datatype,dest,tag,comm)</code> <a class="header-anchor" href="#_5-mpi-send-buf-counter-datatype-dest-tag-comm" aria-label="Permalink to “5. MPI_Send(buf,counter,datatype,dest,tag,comm)”">​</a></h4><ul><li>buf：发送缓冲区的起始地址，可以是数组或结构指针；</li><li>count：非负整数，发送的数据个数；</li><li>datatype：发送数据的数据类型；</li><li>dest：整型，目的的进程号；</li><li>tag：整型，消息标志；comm：MPI 进程组所在的通信域</li></ul><p>含义:向通信域中的 dest 进程发送数据，数据存放在 buf 中，类型是 datatype，个数是 count，这个消息的标志是 tag，用以和本进程向同一目的进程发送的其它消息区别开来。</p><h4 id="_6-mpi-recv-buf-count-datatype-source-tag-comm-status" tabindex="-1">6. <code>MPI_Recv(buf,count,datatype,source,tag,comm,status)</code> <a class="header-anchor" href="#_6-mpi-recv-buf-count-datatype-source-tag-comm-status" aria-label="Permalink to “6. MPI_Recv(buf,count,datatype,source,tag,comm,status)”">​</a></h4><ul><li>source:整型，接收数据的来源，即发送数据进程的进程号；</li><li>status：MPI_Status 结构指针，返回状态信息。</li></ul><p>MPI 调用借口的总数虽然庞大， 但根据实际编写 MPI 的经验， 常用的 MPI 调用的个数确什么有限。 下面是 6 个最基本的 MPI 函数。 1.  MPI_Init(…); 2.  MPI_Comm_size(…); 3.  MPI_Comm_rank(…); 4.  MPI_Send(…); 5.  MPI_Recv(…); 6.  MPI_Finalize(); 我们在此通过一个简单的例子来说明这 6 个 MPI 函数的基本用处。</p><h2 id="重要说明" tabindex="-1">重要说明 <a class="header-anchor" href="#重要说明" aria-label="Permalink to “重要说明”">​</a></h2><h3 id="_1-mpi-标识一条消息的信息包含四个域" tabindex="-1">1.MPI 标识一条消息的信息包含四个域: <a class="header-anchor" href="#_1-mpi-标识一条消息的信息包含四个域" aria-label="Permalink to “1.MPI 标识一条消息的信息包含四个域:”">​</a></h3><ol><li>源:发送进程隐式确定,进程 rank 值唯一标识.</li><li>目的:Send 函数参数确定.</li><li>Tag:Send 函数参数确定, (0,UB) 232-1.</li><li>通信子:缺省 MPI_COMM_WORLD</li><li>Group:有限/N， 有序/Rank [0,1,2,…N-1]</li><li>Contex:Super_tag,用于标识该通讯空间.</li></ol><h3 id="_2-buffer-的使用" tabindex="-1">2. buffer 的使用 <a class="header-anchor" href="#_2-buffer-的使用" aria-label="Permalink to “2. buffer 的使用”">​</a></h3><ol><li>buffer 必须至少可以容纳 count 个由 datatype 指明类型的数据. 如果接收 buf 太小, 将导致溢出、 出错</li></ol><h3 id="_3-消息匹配" tabindex="-1">3. 消息匹配 <a class="header-anchor" href="#_3-消息匹配" aria-label="Permalink to “3. 消息匹配”">​</a></h3><ol><li>–  参数匹配 source,tag,comm/dest,tag,comm.</li><li>–  Source == MPI_ANY_SOURCE： 接收任意处理器来的数据(任意消息来源).</li><li>–  Tag == MPI_ANY_TAG： 匹配任意 tag 值的消息(任意 tag 消息).</li></ol><h3 id="_4-在阻塞式消息传送中不允许-source-dest-否则会导致死锁" tabindex="-1">4. 在阻塞式消息传送中不允许 Source == dest, 否则会导致死锁. <a class="header-anchor" href="#_4-在阻塞式消息传送中不允许-source-dest-否则会导致死锁" aria-label="Permalink to “4. 在阻塞式消息传送中不允许 Source == dest, 否则会导致死锁.”">​</a></h3><h3 id="_5-消息传送被限制在同一个通信域内。" tabindex="-1">5. 消息传送被限制在同一个通信域内。 <a class="header-anchor" href="#_5-消息传送被限制在同一个通信域内。" aria-label="Permalink to “5. 消息传送被限制在同一个通信域内。”">​</a></h3><h3 id="_6-在-send-函数中必须指定唯一的接收者。" tabindex="-1">6. 在 send 函数中必须指定唯一的接收者。 <a class="header-anchor" href="#_6-在-send-函数中必须指定唯一的接收者。" aria-label="Permalink to “6. 在 send 函数中必须指定唯一的接收者。”">​</a></h3>',57)])])}const M=e(o,[["render",l]]);export{P as __pageData,M as default};
